{
  "name": "FitFlow AI",
  "description": "A mobile-first personal fitness assistant that creates custom workout plans, tracks your progress, and answers fitness questions using Gemini AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// User Profile
export interface UserProfile {
  name: string;
  age: number;
  weight: number; // kg
  height: number; // cm
  goal: 'muscle' | 'weight_loss' | 'endurance' | 'flexibility';
  experience: 'beginner' | 'intermediate' | 'advanced';
  equipment: string[]; // e.g., 'dumbbell', 'bodyweight', 'gym'
}

// Workout Data
export interface Exercise {
  name: string;
  sets: number;
  reps: string; // string to allow range "8-12"
  weight?: number;
  notes?: string;
}

export interface WorkoutSession {
  id: string;
  date: string;
  exercises: Exercise[];
  durationMinutes: number;
  notes?: string;
}

// AI Plan
export interface WorkoutPlan {
  name: string;
  description: string;
  routine: Exercise[];
}

// Chat
export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isPlan?: boolean; // If true, the text is a JSON string of a plan
  timestamp: number;
}

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  TRAINER = 'TRAINER',
  LOG = 'LOG',
  PROFILE = 'PROFILE',
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, ChatMessage, WorkoutPlan } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_CHAT = "gemini-3-flash-preview";
const MODEL_PLAN = "gemini-3-flash-preview";

// System instruction for the chat persona
const TRAINER_SYSTEM_INSTRUCTION = `
You are FitFlow, an elite, encouraging, and highly technical personal fitness AI assistant. 
Your goal is to help the user achieve their fitness goals. 
Keep your responses concise and formatted for mobile reading (use bullet points, short paragraphs).
Be motivational but scientifically accurate.
`;

/**
 * Generates a specific workout plan based on user profile and request.
 */
export const generateWorkoutPlan = async (
  profile: UserProfile, 
  focus: string
): Promise<WorkoutPlan | null> => {

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      name: { type: Type.STRING, description: "Creative name for the workout" },
      description: { type: Type.STRING, description: "Brief summary of the focus" },
      routine: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            sets: { type: Type.INTEGER },
            reps: { type: Type.STRING, description: "e.g., '8-12' or '30 sec'" },
            notes: { type: Type.STRING, description: "Form cue or tempo instruction" }
          },
          required: ["name", "sets", "reps"]
        }
      }
    },
    required: ["name", "description", "routine"]
  };

  const prompt = `
    Create a workout plan for a user with these stats:
    - Goal: ${profile.goal}
    - Level: ${profile.experience}
    - Equipment available: ${profile.equipment.join(', ')}

    The workout focus should be: ${focus}.
    Ensure the exercises match the available equipment.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_PLAN,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        systemInstruction: "You are an expert fitness program designer."
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as WorkoutPlan;
  } catch (error) {
    console.error("Error generating plan:", error);
    return null;
  }
};

/**
 * General chat with the fitness assistant.
 */
export const sendChatMessage = async (
  history: ChatMessage[],
  newMessage: string,
  profile: UserProfile
): Promise<string> => {
  // Convert app history to Gemini history format
  // We only take the last 10 messages to save context window and keep it relevant
  const historyContext = history.slice(-10).map(msg => ({
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  // Inject profile context into the latest message invisibly
  const contextPrompt = `
    [User Context: ${profile.age}yo, ${profile.weight}kg, Goal: ${profile.goal}, Equip: ${profile.equipment.join(', ')}]
    User Question: ${newMessage}
  `;

  try {
    const chat = ai.chats.create({
      model: MODEL_CHAT,
      config: {
        systemInstruction: TRAINER_SYSTEM_INSTRUCTION,
      },
      history: historyContext
    });

    const result = await chat.sendMessage({ message: contextPrompt });
    return result.text || "I'm having trouble connecting to the gym server. Try again?";
  } catch (error) {
    console.error("Chat error:", error);
    return "Something went wrong. Please check your connection.";
  }
};

import React from 'react';
import { AppView } from '../types';

