};

export default Navigation;

import React from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { UserProfile, WorkoutSession } from '../types';

interface DashboardProps {
  profile: UserProfile;
  history: WorkoutSession[];
}

const Dashboard: React.FC<DashboardProps> = ({ profile, history }) => {
  // Process history for chart
  const chartData = history
    .slice(-7) // Last 7 sessions
    .map((session, index) => ({
      name: new Date(session.date).toLocaleDateString('en-US', { weekday: 'short' }),
      duration: session.durationMinutes,
      volume: session.exercises.reduce((acc, ex) => acc + (ex.sets * parseInt(ex.reps) * (ex.weight || 0)), 0) / 100 // Scale down volume
    }));

  const totalWorkouts = history.length;
  const totalMinutes = history.reduce((acc, curr) => acc + curr.durationMinutes, 0);

  return (
    <div className="flex flex-col gap-6 pb-24">
      {/* Header */}
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-bold text-white">Hello, {profile.name}</h1>
          <p className="text-slate-400">Ready to crush your {profile.goal} goals?</p>
        </div>
        <div className="w-10 h-10 rounded-full bg-primary flex items-center justify-center text-slate-900 font-bold">
          {profile.name.charAt(0)}
        </div>
      </header>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-surface p-4 rounded-2xl border border-slate-700/50">
          <p className="text-slate-400 text-sm">Total Workouts</p>
          <p className="text-2xl font-bold text-white mt-1">{totalWorkouts}</p>
        </div>
        <div className="bg-surface p-4 rounded-2xl border border-slate-700/50">
          <p className="text-slate-400 text-sm">Minutes Active</p>
          <p className="text-2xl font-bold text-primary mt-1">{totalMinutes}</p>
        </div>
      </div>

      {/* Chart */}
      <div className="bg-surface p-4 rounded-2xl border border-slate-700/50 h-64">
        <h3 className="text-white font-medium mb-4">Activity Trend</h3>
        <ResponsiveContainer width="100%" height="80%">
          <AreaChart data={chartData.length > 0 ? chartData : [{name: 'Mon', duration: 0}]}>
            <defs>
              <linearGradient id="colorDuration" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#a3e635" stopOpacity={0.3}/>
                <stop offset="95%" stopColor="#a3e635" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis dataKey="name" stroke="#94a3b8" tick={{fontSize: 12}} />
            <YAxis stroke="#94a3b8" tick={{fontSize: 12}} />
            <Tooltip 
              contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#fff' }}
              itemStyle={{ color: '#a3e635' }}
            />
            <Area type="monotone" dataKey="duration" stroke="#a3e635" fillOpacity={1} fill="url(#colorDuration)" />
          </AreaChart>
        </ResponsiveContainer>
      </div>

      {/* Quick Actions */}
      <div className="space-y-3">
        <h3 className="text-white font-medium">Quick Stats</h3>
        <div className="bg-surface p-4 rounded-2xl flex justify-between items-center border border-slate-700/50">
           <div>
             <p className="text-slate-400 text-xs">Current Weight</p>
             <p className="text-white font-bold">{profile.weight} kg</p>
           </div>
           <div>
             <p className="text-slate-400 text-xs">Goal</p>
             <p className="text-primary font-bold capitalize">{profile.goal.replace('_', ' ')}</p>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage, WorkoutPlan } from '../types';
import { sendChatMessage, generateWorkoutPlan } from '../services/geminiService';

interface AITrainerProps {
  profile: UserProfile;
}

const AITrainer: React.FC<AITrainerProps> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: `Hi ${profile.name}! I'm FitFlow. I can answer your fitness questions or generate a custom workout plan for you right now. What do you need?`,
      timestamp: Date.now(),
    },
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [mode, setMode] = useState<'chat' | 'plan'>('chat');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    if (mode === 'chat') {
      const responseText = await sendChatMessage(messages, inputText, profile);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
    } else {
      // Plan Generation Mode
      const plan = await generateWorkoutPlan(profile, inputText);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: plan ? JSON.stringify(plan) : "Sorry, I couldn't generate a plan. Please try again with more details.",
        isPlan: !!plan,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
      setMode('chat'); // Reset to chat after generating
    }

    setIsLoading(false);
  };

  const renderPlanCard = (jsonString: string) => {
    try {
      const plan: WorkoutPlan = JSON.parse(jsonString);
      return (
        <div className="bg-slate-800 rounded-xl p-4 my-2 border border-primary/30 w-full">
          <div className="flex justify-between items-start mb-2">
             <h3 className="text-lg font-bold text-primary">{plan.name}</h3>
             <span className="text-xs bg-primary/20 text-primary px-2 py-1 rounded">Plan</span>
          </div>
          <p className="text-sm text-slate-300 mb-4 italic">{plan.description}</p>
          <div className="space-y-2">
            {plan.routine.map((ex, i) => (
              <div key={i} className="flex justify-between items-center bg-slate-900/50 p-2 rounded">
                <div>
                  <p className="font-medium text-white">{ex.name}</p>
                  {ex.notes && <p className="text-xs text-slate-400">{ex.notes}</p>}
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-white">{ex.sets} x {ex.reps}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      );
    } catch (e) {
      return <div className="text-red-400">Error rendering plan.</div>;
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-100px)]">
      {/* Toggle Header */}
      <div className="flex p-1 bg-surface rounded-lg mb-4 mx-4 mt-2 border border-slate-700">
        <button
          onClick={() => setMode('chat')}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
            mode === 'chat' ? 'bg-primary text-slate-900 shadow' : 'text-slate-400'
          }`}
        >
          Chat Coach
        </button>
        <button
          onClick={() => setMode('plan')}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
            mode === 'plan' ? 'bg-primary text-slate-900 shadow' : 'text-slate-400'
          }`}
        >
          Generate Plan
        </button>
      </div>

      {/* Messages Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 space-y-4 no-scrollbar pb-4">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            {msg.role === 'model' && (
              <div className="w-8 h-8 rounded-full bg-primary/20 text-primary flex items-center justify-center mr-2 flex-shrink-0 mt-1">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a2 2 0 0 1 2 2v2a2 2 0 0 1-2 2 2 2 0 0 1-2-2V4a2 2 0 0 1 2-2Z"/><path d="m16 8-2 2"/><path d="m8 8 2 2"/><rect width="16" height="12" x="4" y="12" rx="2"/><path d="M10 16h4"/></svg>
              </div>
            )}

            {msg.isPlan ? (
              renderPlanCard(msg.text)
            ) : (
              <div
                className={`max-w-[80%] p-3 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user'
                    ? 'bg-primary text-slate-900 rounded-br-none'
                    : 'bg-surface text-slate-100 rounded-bl-none border border-slate-700/50'
                }`}
              >
                {msg.text}
              </div>
            )}
          </div>
        ))}
        {isLoading && (
           <div className="flex justify-start">
             <div className="w-8 h-8 mr-2" />
             <div className="bg-surface px-4 py-3 rounded-2xl rounded-bl-none border border-slate-700/50">
               <div className="flex space-x-2">
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" />
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-75" />
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" />
               </div>
             </div>
           </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-background/80 backdrop-blur-sm sticky bottom-0">
        <div className="relative flex items-center">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={mode === 'chat' ? "Ask about form, diet, etc..." : "Describe workout (e.g. Leg day with dumbbells)"}
            className="w-full bg-surface text-white rounded-full py-3 pl-4 pr-12 border border-slate-700 focus:outline-none focus:border-primary transition-colors"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !inputText.trim()}
            className="absolute right-2 p-2 bg-primary rounded-full text-slate-900 hover:bg-lime-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" x2="11" y1="2" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AITrainer;

import React, { useState } from 'react';
import { Exercise, WorkoutSession } from '../types';

interface WorkoutLogProps {
  onSave: (session: WorkoutSession) => void;
}

const WorkoutLog: React.FC<WorkoutLogProps> = ({ onSave }) => {
  const [sessionExercises, setSessionExercises] = useState<Exercise[]>([]);
  const [currentExercise, setCurrentExercise] = useState<Partial<Exercise>>({});
  const [duration, setDuration] = useState<number>(45);

  const addExercise = () => {
    if (currentExercise.name && currentExercise.sets && currentExercise.reps) {
      setSessionExercises([
        ...sessionExercises,
        {
          name: currentExercise.name,
          sets: Number(currentExercise.sets),
          reps: String(currentExercise.reps),
          weight: currentExercise.weight ? Number(currentExercise.weight) : 0,
        } as Exercise,
      ]);
      setCurrentExercise({});
    }
  };

  const handleFinish = () => {
    if (sessionExercises.length === 0) return;

    const newSession: WorkoutSession = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      exercises: sessionExercises,
      durationMinutes: duration,
    };

    onSave(newSession);
    setSessionExercises([]); // Reset
    alert("Workout Saved!");
  };

  return (
    <div className="flex flex-col h-full pb-24 space-y-6">
      <h2 className="text-2xl font-bold text-white">Log Workout</h2>

      {/* Input Card */}
      <div className="bg-surface p-5 rounded-2xl border border-slate-700/50 space-y-4">
        <h3 className="text-primary font-medium text-sm uppercase tracking-wider">Add Exercise</h3>

        <div>
          <label className="block text-xs text-slate-400 mb-1">Exercise Name</label>
          <input
            type="text"
            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:border-primary outline-none"
            placeholder="e.g. Bench Press"
            value={currentExercise.name || ''}
            onChange={e => setCurrentExercise({...currentExercise, name: e.target.value})}
          />
        </div>

        <div className="grid grid-cols-3 gap-3">
          <div>
            <label className="block text-xs text-slate-400 mb-1">Sets</label>
            <input
              type="number"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:border-primary outline-none"
              placeholder="3"
              value={currentExercise.sets || ''}
              onChange={e => setCurrentExercise({...currentExercise, sets: parseInt(e.target.value)})}
            />
          </div>
          <div>
            <label className="block text-xs text-slate-400 mb-1">Reps</label>
            <input
              type="text"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:border-primary outline-none"
              placeholder="12"
              value={currentExercise.reps || ''}
              onChange={e => setCurrentExercise({...currentExercise, reps: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-xs text-slate-400 mb-1">Weight (kg)</label>
            <input
              type="number"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:border-primary outline-none"
              placeholder="0"
              value={currentExercise.weight || ''}
              onChange={e => setCurrentExercise({...currentExercise, weight: parseFloat(e.target.value)})}
            />
          </div>
        </div>

        <button
          onClick={addExercise}
          disabled={!currentExercise.name || !currentExercise.sets || !currentExercise.reps}
          className="w-full bg-slate-700 hover:bg-slate-600 text-white font-medium py-3 rounded-xl transition-colors disabled:opacity-50"
        >
          Add to Session
        </button>
      </div>

      {/* List */}
      <div className="flex-1 overflow-auto">
        <h3 className="text-white font-medium mb-3">Current Session</h3>
        {sessionExercises.length === 0 ? (
          <div className="text-center py-10 text-slate-500 border-2 border-dashed border-slate-800 rounded-xl">
            No exercises added yet.
          </div>
        ) : (
          <div className="space-y-3">
            {sessionExercises.map((ex, idx) => (
              <div key={idx} className="bg-surface p-4 rounded-xl flex justify-between items-center border border-slate-700/50">
                <div>
                  <p className="font-bold text-white">{ex.name}</p>
                  <p className="text-xs text-slate-400">{ex.sets} sets × {ex.reps} {ex.weight ? `@ ${ex.weight}kg` : ''}</p>
                </div>
                <button 
                  onClick={() => setSessionExercises(sessionExercises.filter((_, i) => i !== idx))}
                  className="text-red-400 p-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Finish Button */}
