import React, { useState } from 'react';
import { UserProfile } from '../types';

interface ProfileModalProps {
  onSave: (profile: UserProfile) => void;
}

const ProfileModal: React.FC<ProfileModalProps> = ({ onSave }) => {
  const [formData, setFormData] = useState<Partial<UserProfile>>({
    goal: 'muscle',
    experience: 'beginner',
    equipment: [],
  });
  const [step, setStep] = useState(1);

  const handleNext = () => setStep(step + 1);

  const toggleEquipment = (item: string) => {
    const current = formData.equipment || [];
    if (current.includes(item)) {
      setFormData({ ...formData, equipment: current.filter(i => i !== item) });
    } else {
      setFormData({ ...formData, equipment: [...current, item] });
    }
  };

  const handleFinish = () => {
    if (formData.name && formData.weight && formData.equipment) {
      onSave(formData as UserProfile);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex items-center justify-center p-4">
      <div className="bg-surface w-full max-w-md rounded-3xl p-6 border border-slate-700 shadow-2xl">
        <div className="mb-6 text-center">
          <h2 className="text-2xl font-bold text-white">Setup Profile</h2>
          <div className="flex justify-center mt-2 space-x-2">
            {[1, 2, 3].map(i => (
              <div key={i} className={`h-1 rounded-full transition-all ${i === step ? 'w-8 bg-primary' : 'w-2 bg-slate-700'}`} />
            ))}
          </div>
        </div>

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <label className="text-sm text-slate-400">Name</label>
              <input 
                type="text" 
                className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 focus:border-primary border border-transparent outline-none"
                placeholder="Your Name"
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-slate-400">Weight (kg)</label>
                <input 
                  type="number" 
                  className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 outline-none"
                  placeholder="70"
                  onChange={e => setFormData({...formData, weight: parseFloat(e.target.value)})}
                />
              </div>
              <div>
                <label className="text-sm text-slate-400">Age</label>
                <input 
                  type="number" 
                  className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 outline-none"
                  placeholder="25"
                  onChange={e => setFormData({...formData, age: parseFloat(e.target.value)})}
                />
              </div>
            </div>
            <button 
              onClick={handleNext}
              disabled={!formData.name}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-4 disabled:opacity-50"
            >
              Next
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-4">
            <p className="text-white font-medium">What is your main goal?</p>
            <div className="grid grid-cols-1 gap-3">
              {['muscle', 'weight_loss', 'endurance', 'flexibility'].map(g => (
                <button
                  key={g}
                  onClick={() => setFormData({...formData, goal: g as any})}
                  className={`p-3 rounded-xl border text-left capitalize ${
                    formData.goal === g 
                    ? 'border-primary bg-primary/10 text-primary' 
                    : 'border-slate-700 text-slate-400'
                  }`}
                >
                  {g.replace('_', ' ')}
                </button>
              ))}
            </div>
            <button 
              onClick={handleNext}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-4"
            >
              Next
            </button>
