        )}

        {step === 3 && (
          <div className="space-y-4">
            <p className="text-white font-medium">Available Equipment</p>
            <div className="flex flex-wrap gap-2">
              {['Dumbbells', 'Barbell', 'Bodyweight', 'Kettlebell', 'Pull-up Bar', 'Gym Machines', 'Resistance Bands'].map(item => (
                <button
                  key={item}
                  onClick={() => toggleEquipment(item)}
