              ))}
            </div>
            <button 
              onClick={handleFinish}
              disabled={!formData.equipment?.length}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-6 disabled:opacity-50"
            >
              Start Journey
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

