import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import AITrainer from './components/AITrainer';
import WorkoutLog from './components/WorkoutLog';
import ProfileModal from './components/ProfileModal';
import { AppView, UserProfile, WorkoutSession } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [workoutHistory, setWorkoutHistory] = useState<WorkoutSession[]>([]);

  // Load data from local storage on mount
  useEffect(() => {
    const savedProfile = localStorage.getItem('fitflow_profile');
    const savedHistory = localStorage.getItem('fitflow_history');

    if (savedProfile) setUserProfile(JSON.parse(savedProfile));
    if (savedHistory) setWorkoutHistory(JSON.parse(savedHistory));
  }, []);

  // Save profile
  const handleSaveProfile = (profile: UserProfile) => {
    setUserProfile(profile);
    localStorage.setItem('fitflow_profile', JSON.stringify(profile));
  };

  // Save workout
  const handleSaveWorkout = (session: WorkoutSession) => {
    const newHistory = [...workoutHistory, session];
    setWorkoutHistory(newHistory);
    localStorage.setItem('fitflow_history', JSON.stringify(newHistory));
    setCurrentView(AppView.DASHBOARD);
  };

  // Clear data (for Profile view mostly)
  const handleReset = () => {
      if(confirm("Reset all data? This cannot be undone.")) {
        localStorage.clear();
        window.location.reload();
      }
  };

  if (!userProfile) {
    return <ProfileModal onSave={handleSaveProfile} />;
  }

  return (
    <div className="min-h-screen bg-slate-900 font-sans text-slate-50 selection:bg-primary selection:text-slate-900">
      <main className="max-w-md mx-auto min-h-screen relative bg-slate-900 shadow-2xl overflow-hidden">
        <div className="p-4 pt-6 h-full overflow-y-auto no-scrollbar">
          {currentView === AppView.DASHBOARD && (
            <Dashboard profile={userProfile} history={workoutHistory} />
          )}

          {currentView === AppView.TRAINER && (
            <AITrainer profile={userProfile} />
          )}

          {currentView === AppView.LOG && (
            <WorkoutLog onSave={handleSaveWorkout} />
          )}

          {currentView === AppView.PROFILE && (
             <div className="space-y-6 pb-24">
                <h2 className="text-2xl font-bold">Profile Settings</h2>
                <div className="bg-surface p-4 rounded-xl border border-slate-700/50">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="w-16 h-16 rounded-full bg-primary flex items-center justify-center text-2xl font-bold text-slate-900">
                            {userProfile.name.charAt(0)}
                        </div>
                        <div>
                            <p className="font-bold text-lg">{userProfile.name}</p>
                            <p className="text-slate-400 text-sm capitalize">{userProfile.experience} Athlete</p>
                        </div>
                    </div>
                    <div className="space-y-2 text-sm text-slate-300">
                        <p>Goal: <span className="text-primary capitalize">{userProfile.goal.replace('_', ' ')}</span></p>
                        <p>Weight: <span className="text-white">{userProfile.weight}kg</span></p>
                        <p>Equip: <span className="text-white">{userProfile.equipment.join(', ')}</span></p>
                    </div>
                </div>

                <button 
                    onClick={handleReset}
                    className="w-full border border-red-500/50 text-red-400 py-3 rounded-xl hover:bg-red-500/10 transition-colors"
                >
                    Reset App Data
                </button>
             </div>
          )}
        </div>

        <Navigation currentView={currentView} setView={setCurrentView} />
      </main>
    </div>
  );
};

