import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage, WorkoutPlan } from '../types';
import { sendChatMessage, generateWorkoutPlan } from '../services/geminiService';

interface AITrainerProps {
  profile: UserProfile;
}

const AITrainer: React.FC<AITrainerProps> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: `嗨 ${profile.name}！我是你的 FitFlow 健身助理。我可以回答你的健身疑問，或是幫你安排今天的訓練菜單。你需要什麼協助嗎？`,
      timestamp: Date.now(),
    },
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [mode, setMode] = useState<'chat' | 'plan'>('chat');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    if (mode === 'chat') {
      const responseText = await sendChatMessage(messages, inputText, profile);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
    } else {
      // Plan Generation Mode
      const plan = await generateWorkoutPlan(profile, inputText);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: plan ? JSON.stringify(plan) : "抱歉，我無法生成菜單，請再試著描述詳細一點。",
        isPlan: !!plan,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
      setMode('chat'); // Reset to chat after generating
    }

    setIsLoading(false);
  };

  const renderPlanCard = (jsonString: string) => {
    try {
      const plan: WorkoutPlan = JSON.parse(jsonString);
      return (
        <div className="bg-slate-800 rounded-xl p-4 my-2 border border-primary/30 w-full">
          <div className="flex justify-between items-start mb-2">
             <h3 className="text-lg font-bold text-primary">{plan.name}</h3>
             <span className="text-xs bg-primary/20 text-primary px-2 py-1 rounded">菜單</span>
          </div>
          <p className="text-sm text-slate-300 mb-4 italic">{plan.description}</p>
          <div className="space-y-2">
            {plan.routine.map((ex, i) => (
