import React, { useState } from 'react';
import { UserProfile } from '../types';

interface ProfileModalProps {
  onSave: (profile: UserProfile) => void;
}

const goalMap: Record<string, string> = {
  muscle: '增肌 (Muscle Gain)',
  weight_loss: '減脂 (Weight Loss)',
  endurance: '耐力 (Endurance)',
  flexibility: '柔軟度 (Flexibility)'
};

const equipmentMap: Record<string, string> = {
  'Dumbbells': '啞鈴',
  'Barbell': '槓鈴',
  'Bodyweight': '徒手訓練',
  'Kettlebell': '壺鈴',
  'Pull-up Bar': '單槓',
  'Gym Machines': '健身房機器',
  'Resistance Bands': '彈力帶'
};

const ProfileModal: React.FC<ProfileModalProps> = ({ onSave }) => {
  const [formData, setFormData] = useState<Partial<UserProfile>>({
    goal: 'muscle',
    experience: 'beginner',
    equipment: [],
  });
  const [step, setStep] = useState(1);

  const handleNext = () => setStep(step + 1);

  const toggleEquipment = (item: string) => {
    const current = formData.equipment || [];
    if (current.includes(item)) {
      setFormData({ ...formData, equipment: current.filter(i => i !== item) });
    } else {
      setFormData({ ...formData, equipment: [...current, item] });
    }
  };

  const handleFinish = () => {
    if (formData.name && formData.weight && formData.equipment) {
      onSave(formData as UserProfile);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex items-center justify-center p-4">
      <div className="bg-surface w-full max-w-md rounded-3xl p-6 border border-slate-700 shadow-2xl">
        <div className="mb-6 text-center">
          <h2 className="text-2xl font-bold text-white">建立你的檔案</h2>
          <div className="flex justify-center mt-2 space-x-2">
            {[1, 2, 3].map(i => (
              <div key={i} className={`h-1 rounded-full transition-all ${i === step ? 'w-8 bg-primary' : 'w-2 bg-slate-700'}`} />
            ))}
          </div>
        </div>

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <label className="text-sm text-slate-400">暱稱</label>
              <input 
                type="text" 
                className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 focus:border-primary border border-transparent outline-none"
                placeholder="你的名字"
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-slate-400">體重 (kg)</label>
                <input 
                  type="number" 
                  className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 outline-none"
                  placeholder="70"
                  onChange={e => setFormData({...formData, weight: parseFloat(e.target.value)})}
                />
              </div>
              <div>
                <label className="text-sm text-slate-400">年齡</label>
                <input 
                  type="number" 
                  className="w-full bg-slate-900 text-white p-3 rounded-xl mt-1 outline-none"
                  placeholder="25"
                  onChange={e => setFormData({...formData, age: parseFloat(e.target.value)})}
                />
              </div>
            </div>
            <button 
              onClick={handleNext}
              disabled={!formData.name}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-4 disabled:opacity-50"
            >
              下一步
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-4">
            <p className="text-white font-medium">你的主要目標是什麼？</p>
            <div className="grid grid-cols-1 gap-3">
              {['muscle', 'weight_loss', 'endurance', 'flexibility'].map(g => (
                <button
                  key={g}
                  onClick={() => setFormData({...formData, goal: g as any})}
                  className={`p-3 rounded-xl border text-left ${
                    formData.goal === g 
                    ? 'border-primary bg-primary/10 text-primary' 
                    : 'border-slate-700 text-slate-400'
                  }`}
                >
                  {goalMap[g]}
                </button>
              ))}
            </div>
            <button 
              onClick={handleNext}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-4"
            >
              下一步
            </button>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-4">
            <p className="text-white font-medium">你有哪些器材？(可多選)</p>
            <div className="flex flex-wrap gap-2">
              {Object.keys(equipmentMap).map(item => (
                <button
                  key={item}
                  onClick={() => toggleEquipment(item)}
                  className={`px-4 py-2 rounded-full text-sm border transition-all ${
                    formData.equipment?.includes(item)
                    ? 'bg-primary border-primary text-slate-900 font-bold'
                    : 'bg-transparent border-slate-600 text-slate-400'
                  }`}
                >
                  {equipmentMap[item]}
                </button>
              ))}
            </div>
            <button 
              onClick={handleFinish}
              disabled={!formData.equipment?.length}
              className="w-full bg-primary text-slate-900 font-bold py-3 rounded-xl mt-6 disabled:opacity-50"
            >
              開始旅程
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProfileModal;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import AITrainer from './components/AITrainer';
import WorkoutLog from './components/WorkoutLog';
import ProfileModal from './components/ProfileModal';
import { AppView, UserProfile, WorkoutSession } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [workoutHistory, setWorkoutHistory] = useState<WorkoutSession[]>([]);

  // Load data from local storage on mount
  useEffect(() => {
    const savedProfile = localStorage.getItem('fitflow_profile');
    const savedHistory = localStorage.getItem('fitflow_history');

    if (savedProfile) setUserProfile(JSON.parse(savedProfile));
    if (savedHistory) setWorkoutHistory(JSON.parse(savedHistory));
  }, []);

  // Save profile
  const handleSaveProfile = (profile: UserProfile) => {
    setUserProfile(profile);
    localStorage.setItem('fitflow_profile', JSON.stringify(profile));
  };

  // Save workout
  const handleSaveWorkout = (session: WorkoutSession) => {
    const newHistory = [...workoutHistory, session];
    setWorkoutHistory(newHistory);
    localStorage.setItem('fitflow_history', JSON.stringify(newHistory));
    setCurrentView(AppView.DASHBOARD);
  };

  // Clear data (for Profile view mostly)
  const handleReset = () => {
      if(confirm("確定要重置所有資料嗎？此操作無法復原。")) {
        localStorage.clear();
        window.location.reload();
      }
  };

  const goalMap: Record<string, string> = {
      muscle: '增肌',
      weight_loss: '減脂',
      endurance: '耐力',
      flexibility: '柔軟度'
  };

  const experienceMap: Record<string, string> = {
      beginner: '初學者',
      intermediate: '中階',
      advanced: '進階'
  };

  if (!userProfile) {
    return <ProfileModal onSave={handleSaveProfile} />;
  }

  return (
    <div className="min-h-screen bg-slate-900 font-sans text-slate-50 selection:bg-primary selection:text-slate-900">
      <main className="max-w-md mx-auto min-h-screen relative bg-slate-900 shadow-2xl overflow-hidden">
        <div className="p-4 pt-6 h-full overflow-y-auto no-scrollbar">
          {currentView === AppView.DASHBOARD && (
            <Dashboard profile={userProfile} history={workoutHistory} />
          )}

          {currentView === AppView.TRAINER && (
            <AITrainer profile={userProfile} />
          )}

          {currentView === AppView.LOG && (
            <WorkoutLog onSave={handleSaveWorkout} />
          )}

          {currentView === AppView.PROFILE && (
             <div className="space-y-6 pb-24">
                <h2 className="text-2xl font-bold">個人設定</h2>
                <div className="bg-surface p-4 rounded-xl border border-slate-700/50">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="w-16 h-16 rounded-full bg-primary flex items-center justify-center text-2xl font-bold text-slate-900 uppercase">
                            {userProfile.name.charAt(0)}
                        </div>
                        <div>
                            <p className="font-bold text-lg">{userProfile.name}</p>
                            <p className="text-slate-400 text-sm">{experienceMap[userProfile.experience] || userProfile.experience}</p>
                        </div>
                    </div>
                    <div className="space-y-2 text-sm text-slate-300">
                        <p>目標： <span className="text-primary">{goalMap[userProfile.goal] || userProfile.goal}</span></p>
                        <p>體重： <span className="text-white">{userProfile.weight} kg</span></p>
                        <p>器材： <span className="text-white">{userProfile.equipment.join(', ')}</span></p>
                    </div>
                </div>

                <button 
                    onClick={handleReset}
                    className="w-full border border-red-500/50 text-red-400 py-3 rounded-xl hover:bg-red-500/10 transition-colors"
                >
                    重置所有資料 (Reset)
                </button>
             </div>
          )}
        </div>

        <Navigation currentView={currentView} setView={setCurrentView} />
      </main>
    </div>
  );
};

export default App;

// User Profile
export interface UserProfile {
  name: string;
  age: number;
  weight: number; // kg
  height: number; // cm
  goal: 'muscle' | 'weight_loss' | 'endurance' | 'flexibility';
  experience: 'beginner' | 'intermediate' | 'advanced';
  equipment: string[]; // e.g., 'dumbbell', 'bodyweight', 'gym'
  weeklyPlan?: WeeklyPlan; // New: Store the current weekly plan
}

// Workout Data
export interface Exercise {
  name: string;
  sets: number;
  reps: string; // string to allow range "8-12"
  weight?: number;
  notes?: string;
}

export interface WorkoutSession {
  id: string;
  date: string;
  exercises: Exercise[];
  durationMinutes: number;
  notes?: string;
}

// AI Plan Structure
export interface DayPlan {
  day: string; // "Monday", "Tuesday", etc.
  focus: string; // "Legs", "Push", "Rest"
  routine?: Exercise[]; // Can be empty if rest day
  isRest: boolean;
}

export interface WeeklyPlan {
  id: string;
  startDate: string;
  schedule: DayPlan[];
}

export interface WorkoutPlan {
  name: string;
  description: string;
  routine: Exercise[];
}

// Chat
export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isPlan?: boolean; // If true, the text is a JSON string of a plan
  timestamp: number;
}

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  TRAINER = 'TRAINER',
  LOG = 'LOG',
  PROFILE = 'PROFILE',
  ACTIVE_WORKOUT = 'ACTIVE_WORKOUT', // New View
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, ChatMessage, WorkoutPlan, WeeklyPlan } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_CHAT = "gemini-3-flash-preview";
const MODEL_PLAN = "gemini-3-flash-preview";

// System instruction for the chat persona
const TRAINER_SYSTEM_INSTRUCTION = `
你是一位名為 FitFlow 的頂尖健身 AI 助理。
你的目標是幫助使用者達成健身目標。
請注意：
1. **必須全程使用繁體中文 (Traditional Chinese, Taiwan)** 回答。
2. 回答要簡潔有力，適合手機閱讀（多用列點、短段落）。
3. 語氣要像一位專業、充滿鼓勵性的健身教練 (Personal Trainer)。
4. 根據使用者的身體數據和器材提供科學的建議。
`;

/**
 * Generates a specific workout plan based on user profile and request.
 */
export const generateWorkoutPlan = async (
  profile: UserProfile, 
  focus: string
): Promise<WorkoutPlan | null> => {

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      name: { type: Type.STRING, description: "訓練菜單的創意名稱 (例如：強力胸肌轟炸)" },
      description: { type: Type.STRING, description: "簡短描述訓練重點" },
      routine: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "動作名稱 (中文)" },
            sets: { type: Type.INTEGER },
            reps: { type: Type.STRING, description: "例如：'8-12下' 或 '30秒'" },
            notes: { type: Type.STRING, description: "動作提示或節奏 (中文)" }
          },
          required: ["name", "sets", "reps"]
        }
      }
    },
    required: ["name", "description", "routine"]
  };

  const prompt = `
    請為使用者建立一份健身菜單，使用者數據如下：
    - 目標: ${profile.goal}
    - 程度: ${profile.experience}
    - 可用器材: ${profile.equipment.join(', ')}

    使用者本次想訓練的重點是: "${focus}"。

    請確保：
    1. 動作必須配合使用者擁有的器材。
    2. 內容全部使用繁體中文。
    3. 針對初學者給予較簡單的動作，進階者則給予高強度動作。
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_PLAN,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        systemInstruction: "你是一位專業的健身課表設計師，請輸出繁體中文的 JSON 格式。"
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as WorkoutPlan;
  } catch (error) {
    console.error("Error generating plan:", error);
    return null;
  }
};

/**
 * Generates a full weekly plan
 */
export const generateWeeklyPlan = async (profile: UserProfile): Promise<WeeklyPlan | null> => {
  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      id: { type: Type.STRING },
      startDate: { type: Type.STRING },
      schedule: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING, enum: ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"] },
            focus: { type: Type.STRING, description: "Focus area e.g. 'Push', 'Legs', 'Rest'" },
            isRest: { type: Type.BOOLEAN },
            routine: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  sets: { type: Type.INTEGER },
                  reps: { type: Type.STRING },
                  notes: { type: Type.STRING }
                },
                required: ["name", "sets", "reps"]
              }
            }
          },
          required: ["day", "focus", "isRest"]
        }
      }
    },
    required: ["schedule"]
  };

  const prompt = `
    設計一個為期一週的完整訓練計畫 (Weekly Split)。
    使用者數據:
    - 目標: ${profile.goal}
    - 程度: ${profile.experience}
    - 器材: ${profile.equipment.join(', ')}

    要求：
    1. 必須包含 Monday 到 Sunday 共7天。
    2. 根據程度安排適當的休息日 (isRest: true)。
    3. 動作名稱請用繁體中文。
    4. 確保肌肉群有足夠恢復時間。
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_PLAN,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        systemInstruction: "你是一位專業的週期化訓練教練。"
      }
    });

    const text = response.text;
    if (!text) return null;
    const data = JSON.parse(text);
    return { ...data, id: Date.now().toString(), startDate: new Date().toISOString() } as WeeklyPlan;
  } catch (error) {
    console.error("Error generating weekly plan:", error);
    return null;
  }
}

/**
 * General chat with the fitness assistant.
 */
export const sendChatMessage = async (
  history: ChatMessage[],
  newMessage: string,
  profile: UserProfile
): Promise<string> => {
  // Convert app history to Gemini history format
  const historyContext = history.slice(-10).map(msg => ({
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  const contextPrompt = `
    [背景資訊: 年齡 ${profile.age}, 體重 ${profile.weight}kg, 目標: ${profile.goal}, 器材: ${profile.equipment.join(', ')}]
    使用者問題: ${newMessage}
  `;

  try {
    const chat = ai.chats.create({
      model: MODEL_CHAT,
      config: {
        systemInstruction: TRAINER_SYSTEM_INSTRUCTION,
      },
      history: historyContext
    });

    const result = await chat.sendMessage({ message: contextPrompt });
    return result.text || "連線不穩，就像力竭一樣，請再試一次？";
  } catch (error) {
    console.error("Chat error:", error);
    return "系統發生錯誤，請檢查網路連線。";
  }
};

import React, { useState, useEffect } from 'react';
import { Exercise, WorkoutSession } from '../types';

interface ActiveWorkoutProps {
  routine: Exercise[];
  planName: string;
  onFinish: (session: WorkoutSession) => void;
  onCancel: () => void;
}

const ActiveWorkout: React.FC<ActiveWorkoutProps> = ({ routine, planName, onFinish, onCancel }) => {
  const [currentExerciseIndex, setCurrentExerciseIndex] = useState(0);
  const [completedSets, setCompletedSets] = useState<number[]>(routine.map(() => 0)); // Track completed sets per exercise
  const [timer, setTimer] = useState(0);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [workoutDuration, setWorkoutDuration] = useState(0); // Total workout time in seconds
  const [restTimer, setRestTimer] = useState(0);
  const [isResting, setIsResting] = useState(false);

  // Global Workout Timer
  useEffect(() => {
    const interval = setInterval(() => {
      setWorkoutDuration(prev => prev + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Rest Timer
  useEffect(() => {
    let interval: number;
    if (isResting && restTimer > 0) {
      interval = window.setInterval(() => {
        setRestTimer(prev => prev - 1);
      }, 1000);
    } else if (restTimer === 0 && isResting) {
      setIsResting(false);
      // Play a beep sound or vibrate here in a real app
      if (navigator.vibrate) navigator.vibrate(200);
    }
    return () => clearInterval(interval);
  }, [isResting, restTimer]);

  const currentExercise = routine[currentExerciseIndex];
  const isLastExercise = currentExerciseIndex === routine.length - 1;

  const handleSetComplete = () => {
    const newCompletedSets = [...completedSets];
    newCompletedSets[currentExerciseIndex] += 1;
    setCompletedSets(newCompletedSets);

    // Start Rest Timer (default 60s)
    if (newCompletedSets[currentExerciseIndex] < currentExercise.sets) {
        setRestTimer(60);
        setIsResting(true);
    }
  };

  const handleNextExercise = () => {
    if (!isLastExercise) {
      setCurrentExerciseIndex(prev => prev + 1);
      setIsResting(false);
    } else {
      finishWorkout();
    }
  };

  const finishWorkout = () => {
    const session: WorkoutSession = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      exercises: routine, // In a complex app, we'd track actual weights used
      durationMinutes: Math.ceil(workoutDuration / 60),
      notes: `Completed plan: ${planName}`
    };
    onFinish(session);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 bg-slate-900 z-50 flex flex-col">
      {/* Top Bar */}
      <div className="p-4 flex justify-between items-center bg-surface border-b border-slate-700">
        <button onClick={onCancel} className="text-slate-400 text-sm">離開</button>
        <div className="font-mono text-xl font-bold text-white">{formatTime(workoutDuration)}</div>
        <button onClick={finishWorkout} className="text-primary font-bold text-sm">完成</button>
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto p-6 flex flex-col items-center">

        {/* Progress Bar */}
        <div className="w-full h-1 bg-slate-800 rounded-full mb-8">
           <div 
             className="h-full bg-primary transition-all duration-300" 
             style={{width: `${((currentExerciseIndex) / routine.length) * 100}%`}}
           />
        </div>

        {/* Current Exercise Card */}
        <div className="w-full max-w-sm mb-8 text-center">
            <h2 className="text-3xl font-bold text-white mb-2">{currentExercise.name}</h2>
            <div className="inline-block bg-slate-800 px-4 py-1 rounded-full text-slate-300 text-sm mb-6">
                第 {currentExerciseIndex + 1} / {routine.length} 個動作
            </div>

            <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="bg-surface p-4 rounded-2xl border border-slate-700">
                    <p className="text-slate-400 text-xs uppercase">目標組數</p>
                    <p className="text-2xl font-bold text-white">{currentExercise.sets}</p>
                </div>
                <div className="bg-surface p-4 rounded-2xl border border-slate-700">
                    <p className="text-slate-400 text-xs uppercase">次數/時間</p>
                    <p className="text-2xl font-bold text-primary">{currentExercise.reps}</p>
                </div>
            </div>

            {currentExercise.notes && (
                <p className="text-slate-400 text-sm italic mb-8">💡 "{currentExercise.notes}"</p>
            )}

            {/* Sets Tracker */}
            <div className="flex justify-center gap-2 mb-8">
                {Array.from({length: currentExercise.sets}).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-4 h-4 rounded-full border-2 ${
                            i < completedSets[currentExerciseIndex] 
                            ? 'bg-primary border-primary' 
                            : 'border-slate-600'
                        }`}
                    />
                ))}
            </div>
        </div>

        {/* Rest Timer Overlay */}
        {isResting && (
            <div className="absolute inset-x-4 top-1/3 bg-slate-800/95 backdrop-blur border border-primary/30 p-8 rounded-3xl text-center shadow-2xl animate-in fade-in zoom-in duration-200">
                <p className="text-slate-300 mb-2">休息一下</p>
                <div className="text-6xl font-mono font-bold text-white mb-4">{restTimer}</div>
                <div className="flex gap-4 justify-center">
                    <button onClick={() => setRestTimer(prev => prev + 10)} className="px-4 py-2 bg-slate-700 rounded-full text-white">+10s</button>
                    <button onClick={() => setIsResting(false)} className="px-4 py-2 bg-primary text-slate-900 font-bold rounded-full">跳過</button>
                </div>
            </div>
        )}

      </div>

      {/* Bottom Controls */}
      <div className="p-4 bg-surface border-t border-slate-700 safe-area-inset-bottom">
         {completedSets[currentExerciseIndex] < currentExercise.sets ? (
             <button 
                onClick={handleSetComplete}
                className="w-full bg-slate-100 text-slate-900 font-bold text-lg py-4 rounded-2xl hover:bg-white transition-colors flex items-center justify-center gap-2"
             >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                完成第 {completedSets[currentExerciseIndex] + 1} 組
             </button>
         ) : (
             <button 
                onClick={handleNextExercise}
                className="w-full bg-primary text-slate-900 font-bold text-lg py-4 rounded-2xl hover:bg-lime-400 transition-colors"
             >
                {isLastExercise ? '完成訓練！' : '下一個動作 →'}
             </button>
         )}
      </div>
    </div>
  );
};

export default ActiveWorkout;

