import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage, WorkoutPlan, WeeklyPlan } from '../types';
import { sendChatMessage, generateWorkoutPlan, generateWeeklyPlan } from '../services/geminiService';

interface AITrainerProps {
  profile: UserProfile;
  onUpdateProfile: (p: UserProfile) => void;
}

const AITrainer: React.FC<AITrainerProps> = ({ profile, onUpdateProfile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: `嗨 ${profile.name}！想做點什麼？我可以幫你安排「單次訓練」，也可以幫你規劃完整的「一週課表」。`,
      timestamp: Date.now(),
    },
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [mode, setMode] = useState<'chat' | 'plan' | 'weekly'>('chat');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if ((!inputText.trim() && mode !== 'weekly') || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: mode === 'weekly' ? '請幫我產生一週課表' : inputText,
      timestamp: Date.now(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    if (mode === 'chat') {
      const responseText = await sendChatMessage(messages, inputText, profile);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
    } else if (mode === 'plan') {
      const plan = await generateWorkoutPlan(profile, inputText);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: plan ? JSON.stringify(plan) : "抱歉，無法生成單次菜單。",
        isPlan: !!plan,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, aiMsg]);
      setMode('chat'); 
    } else if (mode === 'weekly') {
      const weeklyPlan = await generateWeeklyPlan(profile);
      if (weeklyPlan) {
        // Save to profile
        const newProfile = { ...profile, weeklyPlan };
        onUpdateProfile(newProfile);

        const aiMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          text: "每週課表已生成並儲存到首頁！你可以隨時查看。",
          timestamp: Date.now(),
        };
        setMessages((prev) => [...prev, aiMsg]);
      } else {
         const aiMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          text: "生成週課表失敗，請稍後再試。",
          timestamp: Date.now(),
        };
        setMessages((prev) => [...prev, aiMsg]);
      }
      setMode('chat');
    }

    setIsLoading(false);
  };

  const renderPlanCard = (jsonString: string) => {
    try {
      const plan: WorkoutPlan = JSON.parse(jsonString);
      return (
        <div className="bg-slate-800 rounded-xl p-4 my-2 border border-primary/30 w-full">
          <div className="flex justify-between items-start mb-2">
             <h3 className="text-lg font-bold text-primary">{plan.name}</h3>
             <span className="text-xs bg-primary/20 text-primary px-2 py-1 rounded">單次菜單</span>
          </div>
          <p className="text-sm text-slate-300 mb-4 italic">{plan.description}</p>
          <div className="space-y-2">
            {plan.routine.map((ex, i) => (
              <div key={i} className="flex justify-between items-center bg-slate-900/50 p-2 rounded">
                <div>
                  <p className="font-medium text-white">{ex.name}</p>
                  {ex.notes && <p className="text-xs text-slate-400">{ex.notes}</p>}
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-white">{ex.sets} 組 x {ex.reps}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      );
    } catch (e) {
      return <div className="text-red-400">無法顯示菜單格式。</div>;
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-100px)]">
      {/* Mode Switcher */}
      <div className="flex gap-2 p-2 overflow-x-auto no-scrollbar mx-2 mt-2">
        <button
          onClick={() => setMode('chat')}
          className={`whitespace-nowrap px-4 py-2 text-sm font-medium rounded-full transition-all border ${
            mode === 'chat' ? 'bg-primary border-primary text-slate-900' : 'border-slate-600 text-slate-400'
          }`}
        >
          對話教練
        </button>
        <button
          onClick={() => setMode('plan')}
          className={`whitespace-nowrap px-4 py-2 text-sm font-medium rounded-full transition-all border ${
            mode === 'plan' ? 'bg-primary border-primary text-slate-900' : 'border-slate-600 text-slate-400'
          }`}
        >
          單次菜單
        </button>
        <button
          onClick={() => {
              setMode('weekly');
              // Auto trigger for better UX if clicking this button
              if(!isLoading) setTimeout(handleSend, 100);
          }}
          className={`whitespace-nowrap px-4 py-2 text-sm font-medium rounded-full transition-all border ${
            mode === 'weekly' ? 'bg-primary border-primary text-slate-900' : 'border-slate-600 text-slate-400'
          }`}
        >
          🪄 生成一週課表
        </button>
      </div>

      {/* Messages Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 space-y-4 no-scrollbar pb-4 pt-2">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            {msg.role === 'model' && (
              <div className="w-8 h-8 rounded-full bg-primary/20 text-primary flex items-center justify-center mr-2 flex-shrink-0 mt-1">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a2 2 0 0 1 2 2v2a2 2 0 0 1-2 2 2 2 0 0 1-2-2V4a2 2 0 0 1 2-2Z"/><path d="m16 8-2 2"/><path d="m8 8 2 2"/><rect width="16" height="12" x="4" y="12" rx="2"/><path d="M10 16h4"/></svg>
              </div>
            )}

            {msg.isPlan ? (
              renderPlanCard(msg.text)
            ) : (
              <div
                className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user'
                    ? 'bg-primary text-slate-900 rounded-br-none'
                    : 'bg-surface text-slate-100 rounded-bl-none border border-slate-700/50'
                }`}
              >
                {msg.text}
              </div>
            )}
          </div>
        ))}
        {isLoading && (
           <div className="flex justify-start">
             <div className="w-8 h-8 mr-2" />
             <div className="bg-surface px-4 py-3 rounded-2xl rounded-bl-none border border-slate-700/50">
               <div className="flex space-x-2">
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" />
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-75" />
                 <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" />
               </div>
             </div>
           </div>
        )}
      </div>

      {/* Input Area */}
      {mode !== 'weekly' && (
        <div className="p-4 bg-background/80 backdrop-blur-sm sticky bottom-0">
            <div className="relative flex items-center">
            <input
                type="text"
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder={mode === 'chat' ? "問我問題..." : "描述想練的部位 (例如：胸)"}
                className="w-full bg-surface text-white rounded-full py-3 pl-4 pr-12 border border-slate-700 focus:outline-none focus:border-primary transition-colors placeholder:text-slate-500"
            />
            <button
                onClick={handleSend}
                disabled={isLoading || !inputText.trim()}
                className="absolute right-2 p-2 bg-primary rounded-full text-slate-900 hover:bg-lime-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" x2="11" y1="2" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            </button>
            </div>
        </div>
      )}
    </div>
  );
};

export default AITrainer;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import AITrainer from './components/AITrainer';
import WorkoutLog from './components/WorkoutLog';
import ProfileModal from './components/ProfileModal';
import ActiveWorkout from './components/ActiveWorkout';
import { AppView, UserProfile, WorkoutSession, Exercise } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [workoutHistory, setWorkoutHistory] = useState<WorkoutSession[]>([]);

  // State for Active Workout
  const [activeRoutine, setActiveRoutine] = useState<Exercise[] | null>(null);
  const [activePlanName, setActivePlanName] = useState<string>("");

  // Load data from local storage on mount
  useEffect(() => {
    const savedProfile = localStorage.getItem('fitflow_profile');
    const savedHistory = localStorage.getItem('fitflow_history');

    if (savedProfile) setUserProfile(JSON.parse(savedProfile));
    if (savedHistory) setWorkoutHistory(JSON.parse(savedHistory));
  }, []);

  // Save profile (handles updates like new Weekly Plan)
  const handleSaveProfile = (profile: UserProfile) => {
    setUserProfile(profile);
    localStorage.setItem('fitflow_profile', JSON.stringify(profile));
  };

  // Save workout
  const handleSaveWorkout = (session: WorkoutSession) => {
    const newHistory = [...workoutHistory, session];
    setWorkoutHistory(newHistory);
    localStorage.setItem('fitflow_history', JSON.stringify(newHistory));

    // Exit active mode
    setActiveRoutine(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const startActiveWorkout = (routine: Exercise[], name: string) => {
    setActiveRoutine(routine);
    setActivePlanName(name);
    setCurrentView(AppView.ACTIVE_WORKOUT);
  };

  // Clear data (for Profile view mostly)
  const handleReset = () => {
      if(confirm("確定要重置所有資料嗎？此操作無法復原。")) {
        localStorage.clear();
        window.location.reload();
      }
  };

  const goalMap: Record<string, string> = {
      muscle: '增肌',
      weight_loss: '減脂',
      endurance: '耐力',
      flexibility: '柔軟度'
  };

  const experienceMap: Record<string, string> = {
      beginner: '初學者',
      intermediate: '中階',
      advanced: '進階'
  };

  if (!userProfile) {
    return <ProfileModal onSave={handleSaveProfile} />;
  }

  // Render Full Screen Active Workout if active
  if (currentView === AppView.ACTIVE_WORKOUT && activeRoutine) {
      return (
          <ActiveWorkout 
            routine={activeRoutine} 
            planName={activePlanName} 
            onFinish={handleSaveWorkout}
            onCancel={() => setCurrentView(AppView.DASHBOARD)}
          />
      );
  }

  return (
    <div className="min-h-screen bg-slate-900 font-sans text-slate-50 selection:bg-primary selection:text-slate-900">
      <main className="max-w-md mx-auto min-h-screen relative bg-slate-900 shadow-2xl overflow-hidden flex flex-col">
        <div className="p-4 pt-6 flex-1 overflow-y-auto no-scrollbar">
          {currentView === AppView.DASHBOARD && (
            <Dashboard 
                profile={userProfile} 
                history={workoutHistory} 
                onStartWorkout={startActiveWorkout}
            />
          )}

          {currentView === AppView.TRAINER && (
            <AITrainer profile={userProfile} onUpdateProfile={handleSaveProfile} />
          )}

          {currentView === AppView.LOG && (
            <WorkoutLog onSave={handleSaveWorkout} />
          )}

          {currentView === AppView.PROFILE && (
             <div className="space-y-6 pb-24">
                <h2 className="text-2xl font-bold">個人設定</h2>
                <div className="bg-surface p-4 rounded-xl border border-slate-700/50">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="w-16 h-16 rounded-full bg-primary flex items-center justify-center text-2xl font-bold text-slate-900 uppercase">
                            {userProfile.name.charAt(0)}
                        </div>
                        <div>
                            <p className="font-bold text-lg">{userProfile.name}</p>
                            <p className="text-slate-400 text-sm">{experienceMap[userProfile.experience] || userProfile.experience}</p>
                        </div>
                    </div>
                    <div className="space-y-2 text-sm text-slate-300">
                        <p>目標： <span className="text-primary">{goalMap[userProfile.goal] || userProfile.goal}</span></p>
                        <p>體重： <span className="text-white">{userProfile.weight} kg</span></p>
                        <p>器材： <span className="text-white">{userProfile.equipment.join(', ')}</span></p>
                    </div>
                </div>

                <button 
                    onClick={handleReset}
                    className="w-full border border-red-500/50 text-red-400 py-3 rounded-xl hover:bg-red-500/10 transition-colors"
                >
                    重置所有資料 (Reset)
                </button>
             </div>
          )}
        </div>

        <Navigation currentView={currentView} setView={setCurrentView} />
      </main>
    </div>
  );
};

export default App;
